// Readers for certificate fixture material generated by scripts/gen-certs.sh.

import { createHash, X509Certificate } from "node:crypto";
import * as fs from "node:fs";
import * as path from "node:path";
import { MTLS_CERTS_DIR } from "../setup/constants.js";
import { certPaths, type ClientCertType } from "./mtls.js";

function leafCert(leaf: ClientCertType): X509Certificate {
  // For chain leaves certPath is the full bundle; X509Certificate parses the
  // first (leaf) certificate in the PEM.
  return new X509Certificate(fs.readFileSync(certPaths(leaf).certPath));
}

/** Lowercase SHA-256 fingerprint (PPL short form, no colons). */
export function fingerprint(leaf: ClientCertType): string {
  return leafCert(leaf).fingerprint256.replaceAll(":", "").toLowerCase();
}

/** Base64-encoded SHA-256 hash of the Subject Public Key Info. */
export function spkiHash(leaf: ClientCertType): string {
  const spkiDer = leafCert(leaf).publicKey.export({ type: "spki", format: "der" });
  return createHash("sha256").update(spkiDer).digest("base64");
}

/** Base64 of the trusted root CA PEM, for the inline `ca` / DOWNSTREAM_MTLS_CA surfaces. */
export function rootCABase64(): string {
  return fs.readFileSync(path.join(MTLS_CERTS_DIR, "root-ca.crt")).toString("base64");
}

/** Base64 of the root CA's CRL PEM, for the inline `crl` / DOWNSTREAM_MTLS_CRL surfaces. */
export function rootCRLBase64(): string {
  return fs.readFileSync(path.join(MTLS_CERTS_DIR, "crl-root.pem")).toString("base64");
}
